// ── Helpers ──────────────────────────────────────────────────

let tmpDirs: string[] = [];
const execAsync = promisify(exec);

beforeAll(() => { setupHermeticGit(); });
afterAll(() => { teardownHermeticGit(); });

async function makeTmpDir(): Promise<string> {
  const raw = await fs.mkdtemp(path.join(os.tmpdir(), 'forge-isolate-test-'));
  const dir = await fs.realpath(raw);
  tmpDirs.push(dir);
  return dir;
}

async function setupForge(dir: string): Promise<void> {
  await fs.mkdir(path.join(dir, '.forge'), { recursive: true });
}

async function makeGitRepo(): Promise<string> {
  const dir = await makeTmpDir();
  await execAsync('git init', { cwd: dir });
  await execAsync('git config user.email "test@forge.dev"', { cwd: dir });
  await execAsync('git config user.name "Forge Test"', { cwd: dir });
  await fs.writeFile(path.join(dir, 'README.md'), '# Test\n');
  await execAsync('git add README.md && git commit -m "initial commit"', { cwd: dir });
  await setupForge(dir);
  return dir;
}

async function writeSpec(dir: string, relPath: string, content = '# Spec'): Promise<string> {
  const full = path.join(dir, relPath);
  await fs.mkdir(path.dirname(full), { recursive: true });
  await fs.writeFile(full, content);
  return full;
}

afterEach(async () => {
  for (const d of tmpDirs) {
    closeDb(d);
    await fs.rm(d, { recursive: true, force: true }).catch(() => {});
  }
  tmpDirs = [];
  mockRunCalls.length = 0;
  mockRunBehavior = 'success';
});

// ── autoDetectConcurrency ────────────────────────────────────

describe('autoDetectConcurrency', () => {
  test('returns at least 1', () => {
    const result = autoDetectConcurrency();
    expect(result).toBeGreaterThanOrEqual(1);
  });

  test('returns at most 5 (CPU cap)', () => {
    const result = autoDetectConcurrency();
    expect(result).toBeLessThanOrEqual(5);
  });

  test('returns a whole number', () => {
    const result = autoDetectConcurrency();
    expect(Number.isInteger(result)).toBe(true);
  });
});

// ── --isolate flag acceptance via runSpecBatch ────────────────

describe('isolate mode batch execution', () => {
  test('sequential batch runs all specs and persists manifest entries', async () => {
    const dir = await makeTmpDir();
    await setupForge(dir);
    await writeSpec(dir, 'specs/a.md', '# A');
    await writeSpec(dir, 'specs/b.md', '# B');

    const specPaths = ['a.md', 'b.md'].map(f => path.join(dir, 'specs', f));
    const specNames = ['a.md', 'b.md'];

    const { results } = await runSpecBatch(
      specPaths,
      specNames,
      { prompt: 'test', sequential: true, quiet: true, cwd: dir },
      1,
      'test-isolate-1',
    );

    expect(results).toHaveLength(2);
    expect(results.every(r => r.status === 'success')).toBe(true);

    const manifest = await loadManifest(dir);
    expect(manifest.specs).toHaveLength(2);
  });

  test('parallel batch respects concurrency parameter', async () => {
    const dir = await makeTmpDir();
    await setupForge(dir);
    await writeSpec(dir, 'specs/a.md', '# A');
    await writeSpec(dir, 'specs/b.md', '# B');
    await writeSpec(dir, 'specs/c.md', '# C');

    const specPaths = ['a.md', 'b.md', 'c.md'].map(f => path.join(dir, 'specs', f));

    const { results } = await runSpecBatch(
      specPaths,
      ['a.md', 'b.md', 'c.md'],
      { prompt: 'test', sequential: false, quiet: true, cwd: dir },
      2,
      'test-isolate-conc',
    );

    expect(results).toHaveLength(3);
    expect(mockRunCalls).toHaveLength(3);
  });
});

